"use client";

import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { motion } from "framer-motion";
import { Lock, Mail, Eye, EyeOff, ShieldCheck } from "lucide-react";
import { AuthLayout } from "@/components/auth-layout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { OAuthButtons } from "@/components/oauth-buttons";

type OAuthProvider = "discord" | "google" | "github";

const oauthMessages: Record<string, string> = {
  cancelled: "Discord authorization was cancelled. Try again when ready.",
  "invalid-state": "Discord login session expired or became invalid. Try again.",
  conflict: "This Discord account is already connected to another account.",
  "email-required": "Discord did not provide an email address required for account creation.",
  "discord-unavailable": "Discord authentication is temporarily unavailable. Try again shortly.",
  "invalid-token": "Discord returned an invalid token. Try again.",
  config: "Discord OAuth is not configured on this server.",
};

export default function LoginPage() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [code, setCode] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [twoFactorRequired, setTwoFactorRequired] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [oauthLoading, setOauthLoading] = useState<OAuthProvider | null>(null);
  const router = useRouter();

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const oauthError = params.get("oauth");
    if (oauthError && oauthMessages[oauthError]) setError(oauthMessages[oauthError]);
  }, []);

  const handleQuickAdminLogin = async () => {
    setError("");
    setLoading(true);
    try {
      const res = await fetch("/api/auth/quick-admin-login", { method: "POST" });
      const data = await res.json();
      if (res.ok) {
        router.push("/dashboard");
      } else {
        setError(data.error || "Quick admin login failed");
      }
    } catch {
      setError("Unable to connect to the authentication service.");
    } finally {
      setLoading(false);
    }
  };

  const handleLogin = async (event: React.FormEvent) => {
    event.preventDefault();
    setError("");
    setLoading(true);

    try {
      const res = await fetch("/api/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password, code: code || undefined }),
      });

      const data = await res.json();
      if (res.ok) {
        router.push("/dashboard");
      } else if (data.twoFactorRequired) {
        setTwoFactorRequired(true);
        setError("Enter your authenticator code to continue.");
      } else {
        setError(data.error || "Login failed");
      }
    } catch {
      setError("Unable to connect to the authentication service.");
    } finally {
      setLoading(false);
    }
  };

  const handleOAuthClick = async (provider: OAuthProvider) => {
    if (provider !== "discord") return;
    setOauthLoading(provider);
    await new Promise((resolve) => setTimeout(resolve, 180));
    window.location.href = "/api/auth/discord";
  };

  return (
    <AuthLayout
      eyebrow="Access portal"
      title="Secure sign in"
      description="Use Discord OAuth or your existing credentials to enter the Script Shield workspace."
      sideTitle="Secure access for developers and admins."
      sideDescription="Continue into a premium dashboard for script protection, licensing, analytics, and security controls."
      points={[
        { title: "OAuth login", description: "Discord authorization with protected session cookies." },
        { title: "2FA support", description: "Authenticator codes when extra verification is required." },
        { title: "Session control", description: "Review devices, sessions, and login history after sign in." },
      ]}
    >
      <motion.div initial={{ opacity: 0, y: 18 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.45 }} className="space-y-5">
        {error && (
          <div className="rounded-2xl border border-red-500/20 bg-red-500/10 px-4 py-3 text-sm font-semibold text-red-200" role="alert">
            {error}
          </div>
        )}

        <div className="relative py-2">
          <div className="absolute inset-0 flex items-center"><span className="w-full border-t border-primary/10" /></div>
          <div className="relative flex justify-center text-[10px] font-black uppercase tracking-[0.22em] text-muted-foreground">Continue with</div>
        </div>

        <OAuthButtons providers={["discord"]} onProviderClick={handleOAuthClick} loadingProvider={oauthLoading} />

        <div className="relative py-2">
          <div className="absolute inset-0 flex items-center"><span className="w-full border-t border-primary/10" /></div>
          <div className="relative flex justify-center text-[10px] font-black uppercase tracking-[0.22em] text-muted-foreground">Or use email</div>
        </div>

        <form onSubmit={handleLogin} className="space-y-4">
          <div className="space-y-1.5">
            <label className="text-xs font-black uppercase tracking-[0.18em] text-muted-foreground">Email Address</label>
            <div className="relative">
              <Mail className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
              <Input type="email" value={email} onChange={(event) => setEmail(event.target.value)} placeholder="name@example.com" className="pl-9" required />
            </div>
          </div>

          <div className="space-y-1.5">
            <label className="text-xs font-black uppercase tracking-[0.18em] text-muted-foreground">Password</label>
            <div className="relative">
              <Lock className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
              <Input type={showPassword ? "text" : "password"} value={password} onChange={(event) => setPassword(event.target.value)} placeholder="Enter your password" className="pl-9 pr-10" required />
              <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-3 text-muted-foreground transition-colors hover:text-white">
                {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
              </button>
            </div>
          </div>

          {twoFactorRequired && (
            <div className="space-y-1.5">
              <label className="text-xs font-black uppercase tracking-[0.18em] text-red-300">Authenticator Code</label>
              <div className="relative">
                <ShieldCheck className="absolute left-3 top-3 h-4 w-4 text-red-300" />
                <Input inputMode="numeric" value={code} onChange={(event) => setCode(event.target.value.replace(/\D/g, "").slice(0, 6))} placeholder="123456" className="pl-9" required />
              </div>
            </div>
          )}

          <Button type="submit" variant="glow" className="h-12 w-full" disabled={loading}>
            {loading ? "Signing in..." : "Sign in"}
          </Button>

          {process.env.NODE_ENV !== "production" && (
            <Button type="button" variant="outline" className="h-11 w-full text-xs" onClick={handleQuickAdminLogin}>
              Quick admin login
            </Button>
          )}
        </form>

        <div className="rounded-2xl border border-primary/10 bg-black/24 p-4 text-center text-sm text-muted-foreground">
          New account?{" "}
          <Link href="/auth/register" className="font-black text-red-200 hover:text-white">
            Create credentials
          </Link>
        </div>
      </motion.div>
    </AuthLayout>
  );
}
