import { NextResponse } from "next/server";
import { decrypt, encrypt } from "@/lib/crypto";
import { createAuditLog } from "@/lib/audit-logger";
import { getClientIp, getRateLimitHeaders, rateLimit } from "@/lib/http";
import {
  consumeOAuthState,
  createOAuthSession,
  isOAuthStateError,
  linkOAuthAccount,
  linkOrCreateOAuthUser,
  normalizeEmail,
  oauthErrorRedirect,
  upsertLinkedOAuthAccount,
} from "@/lib/oauth-helpers";
import {
  DiscordOAuthError,
  discordAvatarUrl,
  discordDisplayName,
  exchangeCodeForToken,
  fetchDiscordUser,
} from "@/lib/discord-oauth";

async function discordUnavailableRedirect(error: unknown) {
  console.error("Discord OAuth callback failed:", error);
  if (error instanceof DiscordOAuthError && error.code === "discord-token-missing") return oauthErrorRedirect("invalid-token");
  return oauthErrorRedirect("discord-unavailable");
}

export async function GET(req: Request) {
  const limited = await rateLimit(`auth:discord:callback:${getClientIp(req)}`, 10, 60 * 1000);
  const headers = getRateLimitHeaders(limited);
  const url = new URL(req.url);
  const code = url.searchParams.get("code");
  const state = url.searchParams.get("state");
  const error = url.searchParams.get("error");

  if (!limited.success) {
    return NextResponse.json({ error: "Too many Discord auth attempts" }, { status: 429, headers });
  }

  if (error === "access_denied" || error === "unauthorized_client") return oauthErrorRedirect("cancelled");
  if (error || !code || !state) return oauthErrorRedirect("error");

  const stateValidation = await consumeOAuthState(state, req);
  if (isOAuthStateError(stateValidation)) return oauthErrorRedirect(stateValidation.error.replace("oauth=", ""));

  try {
    const codeVerifier = stateValidation.record.codeVerifierEncrypted ? decrypt(stateValidation.record.codeVerifierEncrypted) : undefined;
    const tokenData = await exchangeCodeForToken(code, codeVerifier);
    const discordUser = await fetchDiscordUser(tokenData.access_token);
    const email = normalizeEmail(discordUser.email) || `discord-${discordUser.id}@local.invalid`;
    const scopes = tokenData.scope ? tokenData.scope.split(" ").filter(Boolean) : ["identify", "email"];
    const avatarUrl = discordAvatarUrl(discordUser);

    const account = {
      provider: "DISCORD" as const,
      providerAccountId: String(discordUser.id),
      email,
      emailVerified: Boolean(discordUser.email),
      displayName: discordDisplayName(discordUser, discordUser.email),
      avatarUrl,
      accessTokenEncrypted: encrypt(tokenData.access_token),
      refreshTokenEncrypted: tokenData.refresh_token ? encrypt(tokenData.refresh_token) : undefined,
      expiresAt: tokenData.expires_in ? new Date(Date.now() + tokenData.expires_in * 1000) : null,
      scopes,
    };

    const resolved = await linkOrCreateOAuthUser(account, stateValidation.record.userId);
    if (typeof resolved.error === "string") return oauthErrorRedirect(resolved.error);

    const user = await linkOAuthAccount(resolved.user, account);
    await upsertLinkedOAuthAccount(user.id, account);
    await createAuditLog(user.id, "USER_DISCORD_LOGIN", { discordId: discordUser.id, email: user.email }, getClientIp(req), req.headers.get("user-agent") || undefined);

    return createOAuthSession(user, req, "discord");
  } catch (error) {
    return discordUnavailableRedirect(error);
  }
}
