        { title: "Workspace profile", description: "Choose a display name and email for your dashboard." },
        { title: "No secret exposure", description: "OAuth tokens remain handled by the API routes." },
      ]}
    >
      <motion.div initial={{ opacity: 0, y: 18 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.45 }}>
        {error && <div className="mb-4 rounded-2xl border border-red-500/20 bg-red-500/10 px-4 py-3 text-sm font-semibold text-red-200">{error}</div>}

        {loading ? (
          <div className="rounded-2xl border border-primary/10 bg-black/24 p-6 text-center text-sm text-muted-foreground">Loading OAuth session...</div>
        ) : (
          <form onSubmit={(event) => void handleSubmit(event)} className="space-y-5">
            <div className="flex justify-center">
              {currentProvider ? <div className={`flex h-16 w-16 items-center justify-center rounded-2xl shadow-red-glow ${currentProvider.accent}`}>{currentProvider.icon}</div> : null}
            </div>

            <div className="rounded-2xl border border-primary/10 bg-black/24 p-4">
              <p className="text-xs font-black uppercase tracking-[0.2em] text-muted-foreground">Connected account</p>
              <p className="mt-2 break-all text-sm font-bold text-white">{email || "Email required"}</p>
              {avatarUrl && <img src={avatarUrl} alt="OAuth avatar" className="mt-4 h-16 w-16 rounded-2xl border border-primary/20 object-cover" />}
            </div>

