              <div className="space-y-1.5">
                <label className="text-xs font-black uppercase tracking-[0.18em] text-muted-foreground">Email Address</label>
                <Input type="email" value={email} onChange={(event) => setEmail(event.target.value)} placeholder="name@example.com" required />
              </div>
            )}

            <div className="space-y-1.5">
              <label className="text-xs font-black uppercase tracking-[0.18em] text-muted-foreground">Display name</label>
              <div className="relative">
                <User className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input value={username} onChange={(event) => setUsername(event.target.value)} placeholder={currentProvider?.label || "Display name"} className="pl-9" />
