import { NextResponse } from "next/server";
import bcrypt from "bcryptjs";
import { db } from "@/lib/db";
import { decrypt, hashToken } from "@/lib/crypto";
import { createAuditLog } from "@/lib/audit-logger";
import { createSessionToken, deviceNameFromUserAgent, setSessionCookie } from "@/lib/auth-session";
import { getClientIp, getJson, hashIdentifier, rateLimit, verifyCsrf } from "@/lib/http";
import { verifyTotp } from "@/lib/otp";
import { z } from "zod";

const loginSchema = z.object({
  email: z.string().trim().toLowerCase().email().max(255),
  password: z.string().min(1).max(128),
  code: z.string().min(1).max(16).optional(),
});

export async function POST(req: Request) {
  if (!verifyCsrf(req)) {
    return NextResponse.json({ error: "CSRF validation failed" }, { status: 403 });
  }

  const ip = getClientIp(req);
  const userAgent = req.headers.get("user-agent") || undefined;
  const deviceName = deviceNameFromUserAgent(userAgent);
  const limited = await rateLimit(`auth:login:${ip}`, 8, 15 * 60 * 1000);
  if (!limited.success) {
    return NextResponse.json({ error: "Too many login attempts" }, { status: 429, headers: { "X-RateLimit-Reset": limited.reset.toString() } });
  }

  try {
    const body = loginSchema.safeParse(await getJson(req));
    if (!body.success) {
      return NextResponse.json({ error: "Invalid login data", details: body.error.flatten() }, { status: 400 });
    }

    const { email, password, code } = body.data;
    const user = await db.user.findUnique({ where: { email } });

    if (!user) {
      await db.loginAttempt.create({ data: { email, success: false, reason: "USER_NOT_FOUND", ip, userAgent, deviceName } });
      return NextResponse.json({ error: "Invalid credentials" }, { status: 401 });
    }

    if (user.banned) {
      await db.loginAttempt.create({ data: { userId: user.id, email, success: false, reason: "BANNED", ip, userAgent, deviceName } });
      return NextResponse.json({ error: "Account is suspended" }, { status: 403 });
    }

    const isMatch = await bcrypt.compare(password, user.passwordHash);
    if (!isMatch) {
      await db.loginAttempt.create({ data: { userId: user.id, email, success: false, reason: "INVALID_PASSWORD", ip, userAgent, deviceName } });
      return NextResponse.json({ error: "Invalid credentials" }, { status: 401 });
    }

    if (user.twoFactorEnabled) {
      if (!code) {
        return NextResponse.json({ error: "2FA_REQUIRED", twoFactorRequired: true }, { status: 401 });
      }
      if (!verifyTotp(decrypt(user.twoFactorSecretEncrypted!), code)) {
        const recovery = await db.recoveryCode.findFirst({
          where: { userId: user.id, codeHash: hashToken(code.toUpperCase()), consumedAt: null },
        });
        if (!recovery) {
          await db.loginAttempt.create({ data: { userId: user.id, email, success: false, reason: "INVALID_2FA_OR_RECOVERY", ip, userAgent, deviceName } });
          return NextResponse.json({ error: "Invalid 2FA or recovery code" }, { status: 401 });
        }
        await db.recoveryCode.update({ where: { id: recovery.id }, data: { consumedAt: new Date() } });
      }
    }

    const { token } = await createSessionToken(user, req);

    await db.userDevice.upsert({
      where: { userId_fingerprintHash: { userId: user.id, fingerprintHash: hashIdentifier(`${ip}:${userAgent || "unknown"}`) } },
      update: {
        deviceName,
        lastIp: ip,
        lastDeviceInfo: userAgent,
        lastUserAgent: userAgent,
        lastSeenAt: new Date(),
      },
      create: {
        userId: user.id,
        fingerprintHash: hashIdentifier(`${ip}:${userAgent || "unknown"}`),
        deviceName,
        lastIp: ip,
        lastDeviceInfo: userAgent,
        lastUserAgent: userAgent,
      },
    });

    await db.loginAttempt.create({ data: { userId: user.id, email, success: true, ip, userAgent, deviceName } });
    await db.ipReputation.upsert({ where: { ip }, update: { lastSeenAt: new Date(), suspiciousLoginCount: { increment: 0 } }, create: { ip, score: 100, lastSeenAt: new Date() } });
    await createAuditLog(user.id, "USER_LOGIN", { username: user.username, email: user.email }, ip, req.headers.get("user-agent") || undefined);

    const response = NextResponse.json({
      message: "Login successful",
      user: {
        id: user.id,
        username: user.username,
        email: user.email,
        role: user.role,
        discordId: user.discordId,
        githubId: user.githubId,
        avatarUrl: user.avatarUrl,
        twoFactorEnabled: user.twoFactorEnabled,
        isVerified: user.isVerified,
        banned: user.banned,
      },
      token,
    });

    setSessionCookie(response, token);
    return response;
  } catch (error) {
    console.error("Login Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}
