"use client"

import React from "react";
import { MessageCircle, Chrome, Github } from "lucide-react";
import { Button } from "@/components/ui/button";

type OAuthProvider = "discord" | "google" | "github";

interface OAuthButtonsProps {
  providers?: OAuthProvider[];
  compact?: boolean;
  loadingProvider?: OAuthProvider | null;
  onProviderClick?: (provider: OAuthProvider) => void | Promise<void>;
}

const providerConfig: Record<OAuthProvider, { label: string; icon: React.ReactNode; href: string; className: string }> = {
  discord: {
    label: "Continue with Discord",
    icon: <MessageCircle className="h-4 w-4" />,
    href: "/api/auth/discord",
    className: "discord-button border-[#5865F2]/30 bg-[#5865F2]/10 text-white hover:bg-[#5865F2]/25",
  },
  google: {
    label: "Continue with Gmail",
    icon: <Chrome className="h-4 w-4" />,
    href: "/api/auth/google",
    className: "border-[#EA4335]/30 bg-gradient-to-r from-[#EA4335]/10 via-[#FBBC05]/10 to-[#34A853]/10 text-white hover:from-[#EA4335]/20 hover:via-[#FBBC05]/15 hover:to-[#34A853]/15",
  },
  github: {
    label: "Continue with GitHub",
    icon: <Github className="h-4 w-4" />,
    href: "/api/auth/github",
    className: "border-white/10 bg-white/5 text-white hover:bg-white/10",
  },
};

export function OAuthButtons({ providers = ["discord", "google", "github"], compact = false, loadingProvider, onProviderClick }: OAuthButtonsProps) {
  const handleClick = async (provider: OAuthProvider) => {
    if (loadingProvider) return;
    if (onProviderClick) {
      await onProviderClick(provider);
      return;
    }
    window.location.href = providerConfig[provider].href;
  };

  return (
    <div className={compact ? "grid grid-cols-1 gap-3" : "space-y-3"}>
      {providers.map((provider) => (
        <Button
          key={provider}
          type="button"
          variant="outline"
          disabled={loadingProvider === provider}
          className={compact ? `h-12 text-sm ${providerConfig[provider].className}` : `h-12 justify-start ${providerConfig[provider].className}`}
          onClick={() => void handleClick(provider)}
        >
          {loadingProvider === provider ? (
            <span className="mr-2 h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent" />
          ) : (
            <span className="mr-2">{providerConfig[provider].icon}</span>
          )}
          {providerConfig[provider].label}
        </Button>
      ))}
    </div>
  );
}
