"use client";

import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { motion } from "framer-motion";
import { Lock, Mail, Eye, EyeOff, ShieldCheck } from "lucide-react";
import { AuthLayout } from "@/components/auth-layout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { OAuthButtons } from "@/components/oauth-buttons";

type OAuthProvider = "discord" | "google" | "github";

const oauthMessages: Record<string, string> = {
  cancelled: "Discord authorization was cancelled. Try again when ready.",
  "invalid-state": "Discord login session expired or became invalid. Try again.",
  conflict: "This Discord account is already connected to another account.",
  "email-required": "Discord did not provide an email address required for account creation.",
  "discord-unavailable": "Discord authentication is temporarily unavailable. Try again shortly.",
  "invalid-token": "Discord returned an invalid token. Try again.",
  config: "Discord OAuth is not configured on this server.",
};

export default function LoginPage() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [code, setCode] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [twoFactorRequired, setTwoFactorRequired] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [oauthLoading, setOauthLoading] = useState<OAuthProvider | null>(null);
  const router = useRouter();

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const oauthError = params.get("oauth");
    if (oauthError && oauthMessages[oauthError]) setError(oauthMessages[oauthError]);
  }, []);

  const handleQuickAdminLogin = async () => {
    setError("");
    setLoading(true);
    try {
      const res = await fetch("/api/auth/quick-admin-login", { method: "POST" });
      const data = await res.json();
      if (res.ok) {
        router.push("/dashboard");
      } else {
        setError(data.error || "Quick admin login failed");
      }
    } catch {
      setError("Unable to connect to the authentication service.");
    } finally {
      setLoading(false);
    }
  };

  const handleLogin = async (event: React.FormEvent) => {
    event.preventDefault();
    setError("");
    setLoading(true);

    try {
      const res = await fetch("/api/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password, code: code || undefined }),
      });

      const data = await res.json();
      if (res.ok) {
        router.push("/dashboard");
      } else if (data.twoFactorRequired) {
        setTwoFactorRequired(true);
        setError("Enter your authenticator code to continue.");
      } else {
        setError(data.error || "Login failed");
      }
    } catch {
      setError("Unable to connect to the authentication service.");
    } finally {
      setLoading(false);
    }
  };

  const handleOAuthClick = async (provider: OAuthProvider) => {
    if (provider !== "discord") return;
    setOauthLoading(provider);
    await new Promise((resolve) => setTimeout(resolve, 180));
    window.location.href = "/api/auth/discord";
  };

  return (
    <AuthLayout
      eyebrow="Access portal"
      title="Secure sign in"
      description="Use Discord OAuth or your existing credentials to enter the Script Shield workspace."
      sideTitle="Secure access for developers and admins."
      sideDescription="Continue into a premium dashboard for script protection, licensing, analytics, and security controls."
      points={[
        { title: "OAuth login", description: "Discord authorization with protected session cookies." },
        { title: "2FA support", description: "Authenticator codes when extra verification is required." },
        { title: "Session control", description: "Review devices, sessions, and login history after sign in." },
