```ts
import { NextResponse } from "next/server";
import bcrypt from "bcryptjs";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { createSessionToken, deviceNameFromUserAgent, setSessionCookie } from "@/lib/auth-session";
import { getClientIp, getJson, rateLimit, verifyCsrf } from "@/lib/http";
import { z } from "zod";

const registerSchema = z.object({
  username: z.string().trim().min(3).max(32).regex(/^[a-zA-Z0-9_]+$/),
  email: z.string().trim().toLowerCase().email().max(255),
  password: z.string().min(10).max(128),
});

export async function POST(req: Request) {
  if (!verifyCsrf(req)) {
    return NextResponse.json({ error: "CSRF validation failed" }, { status: 403 });
  }

  const ip = getClientIp(req);
  const limited = await rateLimit(`auth:register:${ip}`, 5, 60 * 60 * 1000);
  if (!limited.success) {
    return NextResponse.json({ error: "Too many registration attempts" }, { status: 429, headers: { "X-RateLimit-Reset": limited.reset.toString() } });
  }

  try {
    const body = registerSchema.safeParse(await getJson(req));
    if (!body.success) {
      return NextResponse.json({ error: "Invalid registration data", details: body.error.flatten() }, { status: 400 });
    }

    const { username, email, password } = body.data;
    const [existingEmail, existingUsername] = await Promise.all([
      db.user.findFirst({ where: { email }, select: { id: true } }),
      db.user.findFirst({ where: { username: { equals: username, mode: "insensitive" } }, select: { id: true } }),
    ]);

    if (existingEmail) return NextResponse.json({ error: "Email already exists" }, { status: 409 });
    if (existingUsername) return NextResponse.json({ error: "Username already exists" }, { status: 409 });

    const passwordHash = await bcrypt.hash(password, 12);
    const user = await db.user.create({
      data: {
        username,
        email,
        passwordHash,
        role: process.env.INITIAL_ADMIN_EMAIL?.toLowerCase() === email ? "ADMIN" : "DEVELOPER",
        isVerified: false,
      },
    });

    const userAgent = req.headers.get("user-agent") || undefined;
    const deviceName = deviceNameFromUserAgent(userAgent);
    const { token } = await createSessionToken(user, req, { deviceName });

    await db.loginAttempt.create({ data: { userId: user.id, email: user.email, success: true, reason: "REGISTERED", ip, userAgent, deviceName } });
    await createAuditLog(user.id, "USER_REGISTER", { username, email: user.email, role: user.role }, ip, req.headers.get("user-agent") || undefined);

    const response = NextResponse.json({
      message: "User registered successfully",
      user: {
        id: user.id,
        username: user.username,
        email: user.email,
        role: user.role,
        twoFactorEnabled: user.twoFactorEnabled,
        isVerified: user.isVerified,
      },
      token,
    });

    setSessionCookie(response, token);
    return response;
  } catch (error) {
    console.error("Register Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}
