import { NextResponse } from "next/server";
import { cookies } from "next/headers";
import { clearPendingOAuthCookie, clearSessionCookie, destroySession } from "@/lib/auth-session";
import { getClientIp, getRateLimitHeaders, rateLimit } from "@/lib/http";

export async function POST(req: Request) {
  const cookieStore = await cookies();
  const token = cookieStore.get("token")?.value;
  const limited = await rateLimit(`auth:logout:${token || getClientIp(req)}`, 10, 60 * 1000);
  const headers = getRateLimitHeaders(limited);

  if (!limited.success) {
    return NextResponse.json({ error: "Too many logout attempts" }, { status: 429, headers });
  }

  await destroySession(token);

  const response = NextResponse.json({ message: "Logged out" }, { headers });
  clearSessionCookie(response);
  clearPendingOAuthCookie(response);
  return response;
}
