import { NextResponse } from "next/server";
import { encrypt } from "@/lib/crypto";
import { getClientIp, getRateLimitHeaders, rateLimit } from "@/lib/http";
import { createOAuthState } from "@/lib/oauth-helpers";
import { buildDiscordAuthorizationUrl, generatePkcePair } from "@/lib/discord-oauth";

export async function GET(req: Request) {
  const limited = await rateLimit(`auth:discord:start:${getClientIp(req)}`, 10, 60 * 1000);
  const headers = getRateLimitHeaders(limited);

  if (!limited.success) {
    return NextResponse.json({ error: "Too many Discord auth attempts" }, { status: 429, headers });
  }

  try {
    const pkce = generatePkcePair();
    const stateRecord = await createOAuthState(null, encrypt(pkce.verifier));
    const response = NextResponse.redirect(buildDiscordAuthorizationUrl(stateRecord.state, pkce.challenge));

    for (const [key, value] of Object.entries(headers)) {
      response.headers.set(key, value);
    }

    return response;
  } catch (error) {
    console.error("Discord OAuth start failed:", error);
    return NextResponse.redirect("/auth/login?oauth=config");
  }
}
